 28	import { ExternalLinkSquareAltIcon } from '@patternfly/react-icons';
 29	
 30	import { useDrawerContext } from './hooks/useDrawerContext';
 31	import TemplateExpandableDescription from './TemplateExpandableDescription';
 32	
 33	export const TemplateInfoSection: FC = memo(() => {
 34	  const { t } = useKubevirtTranslation();
 35	  const { createModal } = useModal();
 36	  const { setVM, template, vm } = useDrawerContext();
 37	  const { ns } = useParams<{ ns: string }>();
 38	  const vmNamespace = ns || DEFAULT_NAMESPACE;
 39	
 40	  const notAvailable = t('N/A');
 41	  const displayName = getTemplateName(template);
 42	  const description = getTemplateDescription(template) || notAvailable;
 43	  const documentationUrl = getTemplateDocumentationURL(template);
 44	  const workload = getTemplateWorkload(template);
 45	  const networks = getTemplateNetworks(template);
 46	  const interfaces = getTemplateInterfaces(template);
 47	  const disks = getDisks(vm);
 48	  const isDefaultTemplate = isDefaultVariantTemplate(template);
 49	  const [isTemplateInfoExpanded, setIsTemplateInfoExpanded] = useState(true);
 50	
 51	  return (
 52	    <ExpandableSection
 53	      isExpanded={isTemplateInfoExpanded}
 54	      isIndented
 55	      onToggle={(_event, val) => setIsTemplateInfoExpanded(val)}
 56	      toggleText={t('Template info')}
 57	    >
 58	      <DescriptionList className="pf-v6-c-description-list">
 59	        <VirtualMachineDescriptionItem
 60	          descriptionData={displayName}
 61	          descriptionHeader={t('Operating system')}
 62	        />
 63	        <VirtualMachineDescriptionItem
 64	          descriptionData={`${WORKLOADS_LABELS[workload] ?? t('Other')} ${
 65	            isDefaultTemplate && t('(default)')
 66	          }`}
 67	          descriptionHeader={t('Workload type')}
 68	        />
 69	        <VirtualMachineDescriptionItem
 70	          descriptionData={<TemplateExpandableDescription description={description} />}
 71	          descriptionHeader={t('Description')}
 72	        />
 73	        <VirtualMachineDescriptionItem
 74	          descriptionData={
 75	            documentationUrl ? (
 76	              <Button
 77	                icon={<ExternalLinkSquareAltIcon />}
 78	                iconPosition="right"
 79	                isInline
 80	                size="sm"
 81	                variant={ButtonVariant.link}
 82	              >
 83	                <a href={documentationUrl} rel="noopener noreferrer" target="_blank">
 84	                  {t('Refer to documentation')}
 85	                </a>
 86	              </Button>
 87	            ) : (
 88	              notAvailable
 89	            )
 90	          }
 91	          descriptionHeader={t('Documentation')}
 92	        />
 93	        <AdditionalResources template={template} />
 94	        <VirtualMachineDescriptionItem
 95	          bodyContent={
 96	            <CPUDescription
 97	              cpu={getCPU(vm)}
 98	              helperTextResource={CpuMemHelperTextResources.FutureVM}
 99	            />
100	          }
101	          onEditClick={() =>
102	            createModal(({ isOpen, onClose }) => (
103	              <CPUMemoryModal
104	                isOpen={isOpen}
105	                onClose={onClose}
106	                onSubmit={updateVMCPUMemory(vmNamespace, setVM, setVM)}
107	                templateNamespace={template?.metadata?.namespace}
108	                vm={vm}
109	              />
110	            ))
111	          }
112	          descriptionData={<CPUMemory vm={vm} />}
113	          descriptionHeader={t('CPU | Memory')}
114	          isEdit
115	          isPopover
116	        />
117	        <VirtualMachineDescriptionItem
118	          descriptionData={
119	            <WizardOverviewNetworksTable interfaces={interfaces} networks={networks} />
120	          }
121	          descriptionHeader={t('Network interfaces ({{networks}})', { networks: networks?.length })}
122	        />
123	        <VirtualMachineDescriptionItem
124	          descriptionData={<WizardOverviewDisksTable vm={vm} />}
125	          descriptionHeader={t('Disks ({{disks}})', { disks: disks?.length })}
126	        />
127	      </DescriptionList>
128	    </ExpandableSection>
129	  );
130	});

